// ── b3Ɛq Daily Compliance Status ────────────────────────────
// Checks each tax obligation against today's date
// Returns RED / AMBER / GREEN for each

const today  = new Date();
const year   = today.getFullYear();
const month  = today.getMonth() + 1;
const day    = today.getDate();

const fmt = d => d.toISOString().split('T')[0];
const pad = n => String(n).padStart(2,'0');

// Last day of current month
const lastDay = new Date(year, month, 0).getDate();

// Next month for period filings
const nextMonth = month === 12 ? 1 : month + 1;
const nextYear  = month === 12 ? year + 1 : year;

// Days until a deadline
const daysUntil = dateStr => {
  const d = new Date(dateStr);
  return Math.floor((d - today) / 86400000);
};

// Status logic
const getStatus = days => {
  if (days < 0)  return 'RED';
  if (days <= 3) return 'RED';
  if (days <= 7) return 'AMBER';
  return 'GREEN';
};

const emoji = s => s === 'RED' ? '🔴' : s === 'AMBER' ? '🟡' : '🟢';

// Current month obligations (some already passed this month, show next)
const obligations = [
  {
    id: 'PAYE',
    label: 'PAYE Remittance',
    deadline: `${year}-${pad(month)}-10`,
    action: 'Remit to State IRS / FIRS',
    ref: 'NTA 2025 §152'
  },
  {
    id: 'VAT',
    label: 'VAT Return & Remittance',
    deadline: `${year}-${pad(month)}-21`,
    action: 'File VAT return on TaxPro Max',
    ref: 'VATA / NTA 2025'
  },
  {
    id: 'WHT',
    label: 'WHT Schedule & Remittance',
    deadline: `${year}-${pad(month)}-21`,
    action: 'File Form A + remit to NRS',
    ref: 'WHT Regs 2024'
  },
  {
    id: 'PENSION',
    label: 'Pension Contributions',
    deadline: `${year}-${pad(month)}-07`,
    action: 'Remit to PFAs (7 days after salary)',
    ref: 'PRA 2014'
  },
  {
    id: 'NSITF',
    label: 'NSITF Levy (1%)',
    deadline: `${year}-${pad(month)}-${pad(lastDay)}`,
    action: 'Remit 1% gross payroll to NSITF',
    ref: 'ECA 2010'
  },
  {
    id: 'NHF',
    label: 'NHF Remittance (2.5%)',
    deadline: `${year}-${pad(month)}-07`,
    action: 'Remit to FMBN',
    ref: 'NHF Act'
  },
];

const results = obligations.map(ob => {
  const days   = daysUntil(ob.deadline);
  const status = getStatus(days);
  const daysLabel = days < 0
    ? `${Math.abs(days)} day(s) OVERDUE`
    : days === 0 ? 'DUE TODAY'
    : `${days} day(s) remaining`;
  return { ...ob, days, status, daysLabel };
});

const redCount   = results.filter(r => r.status === 'RED').length;
const amberCount = results.filter(r => r.status === 'AMBER').length;
const greenCount = results.filter(r => r.status === 'GREEN').length;

const overall = redCount > 0 ? 'RED' : amberCount > 0 ? 'AMBER' : 'GREEN';

const lines = [
  `${emoji(overall)} *b3Ɛq Compliance Dashboard — ${today.toLocaleDateString('en-NG', {weekday:'long', day:'numeric', month:'long', year:'numeric'})}*`,
  '',
  ...results.map(r =>
    `${emoji(r.status)} *${r.label}*\n   Deadline: ${r.deadline} (${r.daysLabel})\n   → ${r.action}`
  ),
  '',
  `📊 Summary: 🔴 ${redCount} critical  🟡 ${amberCount} upcoming  🟢 ${greenCount} clear`,
  '',
  redCount > 0 ? '⚠️ Immediate action required — penalties are accruing.' : '',
];

return [{ json: {
  date:         today.toISOString().split('T')[0],
  overall,
  red_count:    redCount,
  amber_count:  amberCount,
  green_count:  greenCount,
  obligations:  results,
  summary_text: lines.filter(l => l !== '').join('\n')
} }];
